import { useState } from "react";
import "./style.css";

function App() {
  const imageData = [
    {
      id: 1,
      title: "Mountain Escape",
      category: "Nature",
      likes: 120,
      url: "https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=400"
    },

    {
      id: 2,
      title: "City Lights",
      category: "Travel",
      likes: 98,
      url: "https://images.unsplash.com/photo-1494526585095-c41746248156?w=400"
    },

    {
      id: 3,
      title: "Ocean Breeze",
      category: "Beach",
      likes: 140,
      url: "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=400"
    },

    {
      id: 4,
      title: "Desert Adventure",
      category: "Travel",
      likes: 88,
      url: "https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=400"
    },

    {
      id: 5,
      title: "Forest Path",
      category: "Nature",
      likes: 110,
      url: "https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=400"
    },

    {
      id: 6,
      title: "Snow Paradise",
      category: "Winter",
      likes: 132,
      url: "https://images.unsplash.com/photo-1482192596544-9eb780fc7f66?w=400"
    },

    {
      id: 7,
      title: "Golden Sunset",
      category: "Sunset",
      likes: 170,
      url: "https://images.unsplash.com/photo-1501785888041-af3ef285b470?w=400"
    },

    {
      id: 8,
      title: "Island Dream",
      category: "Beach",
      likes: 95,
      url: "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=400"
    }
  ];

  const [search, setSearch] = useState("");
  const [darkMode, setDarkMode] = useState(false);

  const filteredImages = imageData.filter((item) =>
    item.title.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className={darkMode ? "container dark" : "container"}>
      <div className="top-section">
        <h1 className="title">Travel Image Gallery</h1>

        <button
          className="dark-btn"
          onClick={() => setDarkMode(!darkMode)}
        >
          {darkMode ? "☀ Light Mode" : "🌙 Dark Mode"}
        </button>
      </div>

      <input
        type="text"
        placeholder="Search images..."
        className="search"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      <p className="count">
        Total Images: {filteredImages.length}
      </p>

      <div className="gallery">
        {filteredImages.map((item) => (
          <div className="card" key={item.id}>
            <img src={item.url} alt={item.title} />

            <div className="card-content">
              <h3>{item.title}</h3>

              <p className="category">{item.category}</p>

              <div className="bottom-section">
                <span>❤️ {item.likes}</span>

                <button className="download-btn">
                  Download
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
